What is the output of the following code fragment?

```cpp
#include <iostream>
using namespace std;
void main() {
  int m = 2, k = 5;
  do {
    if(m == 2)
      continue;
    if(m == 5)
      break;
    cout << m << "*";
  } while(++m <= k);
}
```

What is the output of the following code:

```cpp
#include <iostream>
using namespace std;
void fun() {
  static char var = 'b';
  cout << var + 1;
  var++;
  cout << var;
}
void main() {
  fun();
  fun();
}
```

What is the output of the following C++ code?

```cpp
#include <iostream>
#include <cmath>
using namespace std;
double mo(double a);
void main() {
  int x = 3;
  cout << mo(x) << endl;
}
double mo(double a) {
  return pow(a, 3) / 2;
}
```

What is the output of the following code:

```cpp
#include <iostream>
using namespace std;
int finish(int c) {
  c += 0.5;
  return c;
}
void start(float a, int b) {
  a++;
  ++b;
  cout << finish(a + b) << endl;
}
void main() {
  float x = 1.2;
  float y = 1.2;
  start(x, y);
}
```

What is the output of the following code:

```cpp
#include <iostream>
using namespace std;
int f(int y) {
  return y += 2;
}
void main() {
  int r = 5, s = 13;
  while(r-- > 2) {
    cout << f(s) << " ";
    s -= 3;
  }
}
```

What is the output of the following code:

```cpp
#include <iostream>
using namespace std;
int main() {
    int arr[] = {1, 2, 3, 4, 5};
    cout << arr[2] << endl;
    return 0;
}
```

What is the output of the following code:

```cpp
#include <iostream>
using namespace std;
void fun(int &val, int val2) {
    val2 -= 2;
    val += 3;
}

void main() {
    int a = 4, b = 10;
    fun(b, a);
    cout << a << b << endl;
}
```

What is the output of the following code:

```cpp
#include <iostream>
using namespace std;
int p = 6;
void f1() {
    p += 2;
}

void f2() {
    int p = 2;
    p += 2;
    cout << p;
    ::p += 3;
}

void main() {
    p += 2;
    f1();
    cout << p;
    f2();
    cout << p << endl;
}
```

What is the output of the following code:

```cpp
#include <iostream>
using namespace std;
int x = 7;
void fun(int L) {
    static int x = 3;
    x += L;
    cout << x;
}

void main() {
    for(int r = 0 ; r < 3 ; ++r)
        fun(r);
}
```

What is the output of the following code:

```cpp
#include <iostream>
using namespace std;
void main() {
    int i;
    for(i = 1 ; i < 5 ; i++){
        for(int j = i ; j > 2 ; j--)
            cout << j + i;
    }
}
```

What is the output of the following code?

```cpp
#include <iostream>
using namespace std;
void main() {
    int x = 8;
    if (x++ > 8)
        cout << 1 << endl;
    else
        cout << 0 << endl;
}
```

